    private boolean checkIfCouldDowngrade(String apname) {
        Map<String, App> frontInst = AppManager.getInstalledApplications(apname);
        boolean ifCouldDowngrade = true;
        for (App ins : frontInst.values()) {

            if(!ifCouldDowngrade) break;
            String path = ins.getPath();

            if("/ragic-setup".equals(path)) continue;

            Map<String, String> pathFormNames = AppManager.getFormNamesInPath(apname, ins.getPath(), new UserSuper("superuser@ragic.com"));
            for (Map.Entry<String, String> e : pathFormNames.entrySet()) {
                String[] sec = e.getKey().split("_");

                int si = Encoder.parseInt(sec[0], -1);

                if(si >= 10000) continue;

                APIQuery aq = new APIQuery(apname, path, si);

                APIResults result = aq.getAPIResults();

                if(result.hasMore() && result.getData().size() >= 1000) {
                    ifCouldDowngrade = false;
                    break;
                }

            }
        }

        return ifCouldDowngrade;
    }

